import React, { useState } from 'react';
import { PortalSidebar } from '@/components/portal/PortalSidebar';
import { DashboardHeader } from '@/components/dashboard/DashboardHeader';

export default function PortalLayout({ children }: { children: React.ReactNode }) {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  return (
    <div className="flex h-screen bg-[#08090C] overflow-hidden font-sans selection:bg-blue-500/30">
      
      {/* Desktop & Mobile Sidebar */}
      <PortalSidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col overflow-hidden relative">
        
        {/* Mobile Header (Hidden on Desktop) */}
        <header className="md:hidden h-16 bg-[#0D0E12] border-b border-white/5 flex items-center justify-between px-6 z-40">
          <div className="text-sm font-black text-white uppercase tracking-tighter flex items-center gap-2">
            <span className="w-6 h-6 bg-gradient-to-br from-blue-500 to-teal-400 rounded-lg flex justify-center items-center text-[10px]">YP</span>
            Gurukul
          </div>
          <button 
            className="text-white/40 p-2 hover:text-white transition-colors"
            onClick={() => setSidebarOpen(true)}
          >
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
        </header>

        {/* Global Dashboard Header */}
        <DashboardHeader title="Student portal" />

        {/* Scrollable Content View */}
        <main className="flex-1 overflow-x-hidden overflow-y-auto bg-[#08090C] p-6 lg:p-12 relative z-0 custom-scrollbar">
          <div className="max-w-[1600px] mx-auto">
            {children}
          </div>
        </main>
        
      </div>
    </div>
  );
}
